from openpyxl import load_workbook
import re

file_path = r"C:\Users\Administrator\Desktop\DAEIL_JG\PC&PLC IF_MAP_250814.xlsx"

wb = load_workbook(file_path)

print("="*100)
print("SEARCHING FOR D REGISTER ADDRESSES AND NOISE TEST RELATED DATA")
print("="*100)

all_found_data = {}

for sheet_name in wb.sheetnames:
    ws = wb[sheet_name]
    found_matches = []

    # Search all cells for D4090-D4120 range or noise test keywords
    for row in ws.iter_rows(min_row=1, max_row=ws.max_row, min_col=1, max_col=ws.max_column):
        for cell in row:
            if cell.value is None:
                continue

            cell_str = str(cell.value).strip()

            # Check for D register addresses in range D4090-D4120
            if re.search(r'D40(9\d|1[0-2]\d)', cell_str):
                found_matches.append({
                    'row': cell.row,
                    'col': cell.column,
                    'value': cell_str,
                    'type': 'D-register range'
                })

            # Check for noise test keywords (Korean and English)
            elif any(keyword in cell_str.lower() for keyword in ['noise', '방음', 'inspection', '검사']):
                found_matches.append({
                    'row': cell.row,
                    'col': cell.column,
                    'value': cell_str,
                    'type': 'Noise/Inspection keyword'
                })

    if found_matches:
        all_found_data[sheet_name] = found_matches

# Display results
if all_found_data:
    for sheet_name in all_found_data:
        print(f"\n{'='*100}")
        print(f"Sheet: {sheet_name}")
        print(f"{'='*100}")

        for match in all_found_data[sheet_name]:
            print(f"Row {match['row']:<3} | Col {match['col']:<2} | Type: {match['type']:<25} | Value: {match['value']}")
else:
    print("\nNo D register addresses in D4090-D4120 range or noise test keywords found.")
    print("\nSearching for all 'D' register addresses to show complete map...")

    for sheet_name in wb.sheetnames:
        ws = wb[sheet_name]
        d_registers = []

        for row in ws.iter_rows(min_row=1, max_row=ws.max_row, min_col=1, max_col=ws.max_column):
            for cell in row:
                if cell.value is None:
                    continue
                cell_str = str(cell.value).strip()
                if re.search(r'D\d{4,5}', cell_str):
                    d_registers.append({
                        'row': cell.row,
                        'col': cell.column,
                        'value': cell_str
                    })

        if d_registers:
            print(f"\n{'='*100}")
            print(f"Sheet: {sheet_name} - D Register Addresses Found")
            print(f"{'='*100}")

